def _case_model_counts(model_json_path: Path) -> dict[str, int]:
    payload = _load_json(model_json_path)
    model = payload.get('model') if isinstance(payload.get('model'), dict) else {}
    return {
        'node_count': len([row for row in (model.get('nodes') or []) if isinstance(row, dict)]),
        'element_count': len([row for row in (model.get('elements') or []) if isinstance(row, dict)]),
    }


def _midas_section_library_payload(model_json_path: Path) -> tuple[dict[str, Any], str]:
    payload = _load_json(model_json_path)
    model = payload.get('model') if isinstance(payload.get('model'), dict) else {}
    metadata = model.get('metadata') if isinstance(model.get('metadata'), dict) else {}
    section_library = metadata.get('section_library') if isinstance(metadata.get('section_library'), dict) else {}
    if section_library:
        return section_library, 'embedded metadata'
    sections = [row for row in (model.get('sections') or []) if isinstance(row, dict)]
    elements = [row for row in (model.get('elements') or []) if isinstance(row, dict)]
    if not sections or not callable(_derive_section_productization_metadata):
        return {}, ''
    try:
        derived = _derive_section_productization_metadata(
            sections=sections,
            elements=elements,
            design_section_rows=[row for row in (metadata.get('design_sections') or []) if isinstance(row, dict)],
            section_color_rows=[row for row in (metadata.get('section_colors') or []) if isinstance(row, dict)],
            section_scale_rows=[row for row in (metadata.get('section_scales') or []) if isinstance(row, dict)],
        )
    except Exception:
        return {}, ''
    return (derived if isinstance(derived, dict) else {}), 'viewer fallback derived'


def _midas_load_pattern_library_payload(model_json_path: Path) -> tuple[dict[str, Any], str]:
    payload = _load_json(model_json_path)
    model = payload.get('model') if isinstance(payload.get('model'), dict) else {}
    metadata = model.get('metadata') if isinstance(model.get('metadata'), dict) else {}
    load_pattern_library = metadata.get('load_pattern_library') if isinstance(metadata.get('load_pattern_library'), dict) else {}
    if load_pattern_library:
        return load_pattern_library, 'embedded metadata'
    if not callable(derive_load_pattern_productization_for_model_payload):
        if callable(derive_load_productization_from_raw_combination_payload):
            try:
                recovered = derive_load_productization_from_raw_combination_payload(payload)
            except Exception:
                recovered = {}
            recovered_pattern = recovered.get('load_pattern_library') if isinstance(recovered.get('load_pattern_library'), dict) else {}
            if recovered_pattern:
                return recovered_pattern, 'viewer fallback raw recovery'
        return {}, ''
    try:
        derived = derive_load_pattern_productization_for_model_payload(payload)
    except Exception:
        derived = {}
    if isinstance(derived, dict) and derived:
        provenance = str(derived.get('provenance', '') or '')
        if provenance == 'combination_only_raw_recovery':
            return derived, 'viewer fallback raw recovery'
        return derived, 'viewer fallback derived'
    if callable(derive_load_productization_from_raw_combination_payload):
        try:
            recovered = derive_load_productization_from_raw_combination_payload(payload)
        except Exception:
            recovered = {}
        recovered_pattern = recovered.get('load_pattern_library') if isinstance(recovered.get('load_pattern_library'), dict) else {}
        if recovered_pattern:
            return recovered_pattern, 'viewer fallback raw recovery'
    return {}, ''


