def _default_case_catalog_entries(
    *,
    out_dir: Path,
    release_gap_path: Path,
    commercial_workflow_breadth_report_path: Path,
    export_report_path: Path,
    change_summary_path: Path,
    changes_path: Path,
    design_dataset_path: Path,
    model_json_path: Path,
    execution_manifest_path: Path,
    execution_status_path: Path,
    committee_package_path: Path,
) -> list[dict[str, Any]]:
    empty_bundle = _empty_release_bundle()
    entries: list[dict[str, Any]] = []
    local_source_dir = REPO_ROOT / 'implementation/phase1/open_data/midas/quality_corpus/raw'
    bridge_source_dir = REPO_ROOT / 'implementation/phase1/open_data/midas/quality_corpus/bridged'
    committee_package_payload_full = _load_json(committee_package_path)
    committee_artifacts = (
        committee_package_payload_full.get('artifacts')
        if isinstance(committee_package_payload_full.get('artifacts'), dict)
        else {}
    )
    committee_dashboard_html = Path(
        str(
            committee_artifacts.get(
                'committee_dashboard_html',
                REPO_ROOT / 'implementation/phase1/release/committee_review/committee_review_dashboard.html',
            )
        )
    )
    analysis_gallery_onepage_html = out_dir / 'analysis_evidence_gallery_onepage.html'
    pbd_package_json = REPO_ROOT / 'implementation/phase1/release/pbd_review/pbd_review_package_report.json'
    drift_png = REPO_ROOT / 'implementation/phase1/release/pbd_review/drift_envelope_7eq.png'
    hysteresis_png = REPO_ROOT / 'implementation/phase1/release/pbd_review/core_wall_hysteresis.png'

    def _source_local_archive(source_id: str) -> tuple[dict[str, Any], dict[str, str]]:
        archive_path = local_source_dir / f'{source_id}.zip'
        if not archive_path.exists():
            return (
                {
                    'local_archive_cached': False,
                    'local_archive_member_count': 0,
                    'local_archive_preview': [],
                },
                {},
            )
        preview_names: list[str] = []
        member_count = 0
        suffix_counts: dict[str, int] = {}
        try:
            with zipfile.ZipFile(archive_path) as zip_file:
                names = zip_file.namelist()
                member_count = len(names)
                preview_names = [str(name) for name in names[:12]]
                for name in names:
                    suffix = Path(str(name)).suffix.lower() or '(no_ext)'
                    suffix_counts[suffix] = int(suffix_counts.get(suffix, 0)) + 1
        except zipfile.BadZipFile:
            preview_names = ['bad zip archive']
        binary_model_count = int(sum(suffix_counts.get(ext, 0) for ext in ('.mcb', '.meb', '.mmbx')))
        geometry_candidate_count = int(sum(suffix_counts.get(ext, 0) for ext in ('.3dm', '.gh')))
        if binary_model_count > 0:
            readiness_hint = 'native model binary candidate detected'
        elif geometry_candidate_count > 0:
            readiness_hint = 'cad/parametric geometry candidate detected'
        elif member_count > 0:
            readiness_hint = 'archive cached / parser pending'
        else:
            readiness_hint = 'archive cached / unreadable members'
        return (
            {
                'local_archive_cached': True,
                'local_archive_path': str(archive_path),
                'local_archive_member_count': int(member_count),
                'local_archive_preview': preview_names,
                'local_archive_extension_label': _label_counts(suffix_counts),
                'local_archive_binary_model_candidate_count': binary_model_count,
                'local_archive_geometry_candidate_count': geometry_candidate_count,
                'adapter_readiness_hint': readiness_hint,
            },
            {'local_archive_zip': str(archive_path)},
        )

    def _viewer_entry(
        entry_id: str,
        *,
        title: str,
        note: str,
        status_label: str,
        status_tone: str,
        model_path: Path,
        dataset_path: Path,
        root_output: bool,
        release_gap_payload: dict[str, Any],
        export_report_payload: dict[str, Any],
        change_summary_payload: dict[str, Any],
        changes_payload: dict[str, Any],
        execution_manifest_payload: dict[str, Any],
        execution_status_payload: dict[str, Any],
        committee_package_payload: dict[str, Any],
        has_ai_overlay: bool,
        extra_case_context: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        counts = _case_model_counts(model_path)
        case_context = {
            'case_id': entry_id,
            'case_title': title,
            'case_note': note,
            'status_label': status_label,
            'status_tone': status_tone,
            'has_ai_overlay': has_ai_overlay,
            'model_path': str(model_path),
            'dataset_path': str(dataset_path),
        }
        if isinstance(extra_case_context, dict):
            case_context.update(extra_case_context)
        return {
            'entry_id': entry_id,
            'entry_kind': 'viewer',
            'catalog_group': '3D Viewable Cases',
            'title': title,
            'note': note,
            'status_label': status_label,
            'status_tone': status_tone,
            'has_3d': True,
            'has_ai_overlay': has_ai_overlay,
            'node_count': counts['node_count'],
            'element_count': counts['element_count'],
            'output_html_path': (out_dir / 'structural_optimization_viewer.html') if root_output else (out_dir / 'entries' / f'{entry_id}.html'),
            'output_json_path': (out_dir / 'structural_optimization_viewer.json') if root_output else (out_dir / 'entries' / f'{entry_id}.json'),
            'release_gap_payload': release_gap_payload,
            'export_report_payload': export_report_payload,
            'change_summary_payload': change_summary_payload,
            'changes_payload': changes_payload,
            'execution_manifest_payload': execution_manifest_payload,
            'execution_status_payload': execution_status_payload,
            'committee_package_payload': committee_package_payload,
            'model_json_path': model_path,
            'dataset_npz_path': dataset_path,
            'case_context': case_context,
        }

    def _artifact_entry(
        entry_id: str,
        *,
        title: str,
        note: str,
        artifact_path: Path,
        group: str = 'AI Analysis & Optimization Data',
        extra_artifact_paths: dict[str, str] | None = None,
        extra_metadata: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        artifact_payload = _load_json(artifact_path)
        summary_block = artifact_payload.get('summary') if isinstance(artifact_payload.get('summary'), dict) else {}
        if not summary_block and isinstance(artifact_payload.get('metrics'), dict):
            summary_block = artifact_payload.get('metrics') or {}
        preview_items = {
            str(key): summary_block[key]
            for key in list(summary_block.keys())[:6]
        }
        reason_code = str(artifact_payload.get('reason_code', '') or artifact_payload.get('report_family', '') or 'artifact')
        contract_pass = bool(artifact_payload.get('contract_pass', True))
        artifact_paths = {'artifact_json': str(artifact_path)}
        artifact_paths.update(extra_artifact_paths or {})
        return {
            'entry_id': entry_id,
            'entry_kind': 'placeholder',
            'catalog_group': group,
            'title': title,
            'note': note,
            'status_label': reason_code,
            'status_tone': 'ok' if contract_pass else 'warn',
            'has_3d': False,
            'has_ai_overlay': True,
            'output_html_path': out_dir / 'entries' / f'{entry_id}.html',
            'output_json_path': out_dir / 'entries' / f'{entry_id}.json',
            'metadata': {
                'artifact_path': str(artifact_path),
                'reason_code': reason_code,
                'contract_pass': contract_pass,
                'top_level_keys': list(artifact_payload.keys())[:12],
                'summary_preview': preview_items,
                **(extra_metadata or {}),
            },
            'artifact_paths': artifact_paths,
        }

