    def _make_606m_compare_reason_context(
        release_gap_payload: dict[str, Any] | None,
        change_summary_payload: dict[str, Any] | None,
    ) -> dict[str, str]:
        gap_summary = (
            release_gap_payload.get('summary', {})
            if isinstance(release_gap_payload, dict) and isinstance(release_gap_payload.get('summary'), dict)
            else {}
        )
        change_rows = (
            change_summary_payload.get('change_summary_rows', [])
            if isinstance(change_summary_payload, dict) and isinstance(change_summary_payload.get('change_summary_rows'), list)
            else []
        )
        valid_rows = [row for row in change_rows if isinstance(row, dict)]
        cost_delta_total = _safe_float(gap_summary.get('cost_proxy_delta_sum', 0.0))
        constructability_delta_total = _safe_float(gap_summary.get('constructability_delta_sum', 0.0))
        max_dcr_after = _safe_float(gap_summary.get('max_dcr_after_max', 0.0))
        if valid_rows and cost_delta_total == 0.0:
            cost_delta_total = sum(_safe_float(row.get('cost_proxy_delta_sum', 0.0)) for row in valid_rows)
        if valid_rows and constructability_delta_total == 0.0:
            constructability_delta_total = sum(
                _safe_float(row.get('constructability_delta_sum', 0.0)) for row in valid_rows
            )
        if valid_rows and max_dcr_after == 0.0:
            max_dcr_after = max(_safe_float(row.get('max_dcr_after_max', 0.0)) for row in valid_rows)

        zone_totals: Counter[str] = Counter()
        member_totals: Counter[str] = Counter()
        story_totals: Counter[str] = Counter()
        for row in valid_rows:
            weight = abs(_safe_float(row.get('cost_proxy_delta_sum', 0.0)))
            zone_totals[str(row.get('zone_label', 'n/a') or 'n/a')] += weight
            member_totals[str(row.get('member_type', 'n/a') or 'n/a')] += weight
            story_value = str(row.get('story_band_label', '') or row.get('story_band', '') or '').strip()
            if story_value:
                if not story_value.startswith('S') and story_value.isdigit():
                    story_value = f"S{int(story_value):02d}"
                story_totals[story_value] += weight
        top_zone = zone_totals.most_common(1)[0][0] if zone_totals else 'n/a'
        top_member_type = member_totals.most_common(1)[0][0] if member_totals else 'n/a'
        top_story_band = story_totals.most_common(1)[0][0] if story_totals else 'n/a'
        row_count = len(valid_rows)
        reason_snapshot_parts = [
            f"top zone={top_zone}",
            f"top member={top_member_type}",
            f"top story={top_story_band}",
            f"rows={row_count}",
        ]
        if cost_delta_total:
            reason_snapshot_parts.append(f"cost={_format_result_metric(cost_delta_total, decimals=1)}")
        return {
            'cost_delta_label': _format_result_metric(cost_delta_total, decimals=3),
            'constructability_delta_label': _format_result_metric(constructability_delta_total, decimals=3),
            'max_dcr_after_compare_label': _format_result_metric(max_dcr_after, decimals=3),
            'top_zone_label': top_zone,
            'top_member_type_label': top_member_type,
            'top_story_band_label': top_story_band,
            'compare_change_rows_label': str(row_count),
            'compare_reason_snapshot_label': ' | '.join(reason_snapshot_parts),
        }

    def _make_midas_release_context(
        *,
        model_path: Path,
        release_gap_payload: dict[str, Any],
        export_report_payload: dict[str, Any],
        execution_status_payload: dict[str, Any],
        change_summary_payload: dict[str, Any],
    ) -> dict[str, Any]:
        gap_summary = release_gap_payload.get('summary') if isinstance(release_gap_payload.get('summary'), dict) else {}
        export_summary = export_report_payload.get('summary') if isinstance(export_report_payload.get('summary'), dict) else {}
        exec_status_summary = execution_status_payload.get('summary') if isinstance(execution_status_payload.get('summary'), dict) else {}
        change_rows = change_summary_payload.get('change_summary_rows') if isinstance(change_summary_payload.get('change_summary_rows'), list) else []
        return {
            'direct_patch_label': str(int(export_summary.get('direct_patch_change_count', 0) or 0)),
            'audit_packets_label': str(int(export_summary.get('audit_review_packet_count', 0) or 0)),
            'queue_pending_label': str(int(export_summary.get('audit_review_queue_pending_count', 0) or 0)),
            'blocked_tasks_label': str(int(exec_status_summary.get('blocked_task_count', 0) or 0)),
            'change_rows_label': str(len([row for row in change_rows if isinstance(row, dict)])),
            'measured_chain_label': f"{float(gap_summary.get('measured_chain_total_minutes', 0.0) or 0.0):.1f} min",
            'delivery_boundary_label': str(gap_summary.get('mgt_export_delivery_boundary', 'n/a') or 'n/a'),
            'solver_breadth_summary_line': str(gap_summary.get('solver_breadth_summary_line', '') or '').strip(),
            'structural_contact_summary_line': str(gap_summary.get('structural_contact_summary_line', '') or '').strip(),
            'general_fe_contact_matrix_summary_line': str(gap_summary.get('general_fe_contact_matrix_summary_line', '') or '').strip(),
            'foundation_soil_link_summary_line': str(gap_summary.get('foundation_soil_link_summary_line', '') or '').strip(),
            'midas_kds_geometry_bridge_summary_line': str(gap_summary.get('midas_kds_geometry_bridge_summary_line', '') or '').strip(),
            **_make_midas_section_library_context(model_path),
            **_make_midas_load_pattern_context(model_path),
        }

