    def _preview_fidelity_fields(summary: dict[str, Any]) -> dict[str, str]:
        preview_state_label = str(summary.get('preview_state_label', 'n/a') or 'n/a')
        surface_status_label = str(summary.get('preview_surface_status_label', 'n/a') or 'n/a')
        preview_segments = int(summary.get('preview_segment_count', 0) or 0)
        preview_points = int(summary.get('preview_point_count', 0) or 0)
        topology_ready = bool(summary.get('topology_preview_ready', False))
        topology_readiness_label = str(summary.get('topology_readiness_label', '') or '')
        preview_exactness_label = str(summary.get('preview_exactness_label', '') or '')
        exact_topology_candidate = bool(summary.get('exact_topology_candidate', False))
        exact_topology_promoted = bool(summary.get('exact_topology_promoted', False))

        payload_exact_topology = topology_readiness_label.startswith('payload-exact')

        if preview_state_label == 'verified preview':
            fidelity_tier = 'verified-preview'
            fidelity_label = 'verified preview'
            fidelity_note = 'full bridge 수준까지는 아니지만, viewer에 바로 써도 되는 검증된 preview입니다.'
        elif exact_topology_promoted or preview_exactness_label == 'exact topology promoted':
            fidelity_tier = 'exact-topology-promoted'
            fidelity_label = 'exact recovered topology promoted'
            fidelity_note = 'payload topology를 넘어 exact recovered topology 단계까지 올라온 상태입니다. 마지막 verified preview 연결만 남겨 둔 단계로 봐도 됩니다.'
        elif exact_topology_candidate or preview_exactness_label == 'exact topology candidate':
            fidelity_tier = 'exact-topology-candidate'
            fidelity_label = 'exact recovered topology candidate'
            fidelity_note = 'member-add topology와 path/reference closure가 exact 후보 수준까지 올라와서, 일반 payload-exact preview보다 한 단계 직접적인 상태입니다.'
        elif payload_exact_topology:
            fidelity_tier = 'payload-exact-preview'
            fidelity_label = 'payload-exact member-add preview'
            fidelity_note = 'member-add topology는 payload table 기준으로 exact하게 읽었지만, verified recovered topology로 부르기 전 마지막 confidence gate가 남아 있습니다.'
        elif topology_ready or surface_status_label.startswith('topology-grounded'):
            fidelity_tier = 'topology-grounded-preview'
            fidelity_label = 'topology-grounded preview'
            fidelity_note = 'table-local member-add topology까지 반영된 preview라 단순 point cloud보다 신뢰도가 높습니다.'
        elif preview_state_label == 'unverified hint preview':
            fidelity_tier = 'hint-guided-preview'
            fidelity_label = 'hint-guided preview'
            fidelity_note = 'NODE/ELEM 힌트 기반 preview라 전체 형상 감은 주지만 exact member topology는 아직 아닙니다.'
        elif preview_state_label == 'unverified raw preview':
            fidelity_tier = 'raw-preview'
            fidelity_label = 'raw preview'
            fidelity_note = 'raw point/segment scan 기반이라 참고용 spatial silhouette 수준으로 보는 게 맞습니다.'
        else:
            fidelity_tier = 'heuristic-preview'
            fidelity_label = 'heuristic preview'
            fidelity_note = 'heuristic preview 단계라 exact topology보다 shape reading 중심으로 보는 상태입니다.'

        if preview_segments <= 6 or preview_points <= 8:
            density_label = 'sparse preview geometry'
            density_tier = 'sparse'
            visibility_label = 'sparse assist on'
            visibility_note = '부재 수가 적어서 3D에서 endpoint dot과 heavier edge를 켜 두었습니다.'
        elif preview_segments <= 24 or preview_points <= 24:
            density_label = 'light preview geometry'
            density_tier = 'light'
            visibility_label = 'light assist on'
            visibility_note = '중간 밀도 preview라 선 가독성을 약간 높여 보여줍니다.'
        elif preview_segments <= 80:
            density_label = 'moderate preview geometry'
            density_tier = 'moderate'
            visibility_label = 'standard preview visibility'
            visibility_note = 'preview geometry가 충분해 기본 가독성 설정으로 읽을 수 있습니다.'
        else:
            density_label = 'rich preview geometry'
            density_tier = 'rich'
            visibility_label = 'standard preview visibility'
            visibility_note = 'preview density가 높아 full-model에 가까운 읽기성이 확보된 상태입니다.'

        if fidelity_tier == 'verified-preview':
            hidden_detail_label = 'full bridge처럼 모든 section/panel detail을 다 담은 것은 아니지만, 현재 preview 자체는 검증된 상태입니다.'
        elif fidelity_tier == 'exact-topology-promoted':
            hidden_detail_label = 'exact recovered topology 단계까지는 올라왔지만, 아직 full authoring bridge detail과 verified preview 연결은 남아 있을 수 있습니다.'
        elif fidelity_tier == 'exact-topology-candidate':
            hidden_detail_label = 'exact recovered topology 후보 수준까지는 왔지만, verified preview로 부르기 전 마지막 confidence gate는 남아 있습니다.'
        elif fidelity_tier == 'payload-exact-preview':
            hidden_detail_label = 'payload 내부 member-add topology는 exact하지만, verified recovered topology나 full bridge detail까지 확보된 상태는 아닙니다.'
        elif fidelity_tier == 'topology-grounded-preview':
            hidden_detail_label = 'member-add topology는 따라가지만, section thickness·secondary members·surface detail은 아직 생략될 수 있습니다.'
            if topology_readiness_label.startswith('payload-exact'):
                hidden_detail_label = 'payload 내부 member-add topology는 exact하게 읽었지만, full-file verified topology나 full bridge detail까지 확보된 상태는 아닙니다.'
        elif fidelity_tier == 'hint-guided-preview':
            hidden_detail_label = 'NODE/ELEM 힌트로 복구한 골격만 보입니다. exact connectivity와 많은 secondary members는 아직 빠질 수 있습니다.'
        elif fidelity_tier == 'raw-preview':
            hidden_detail_label = 'raw scan silhouette 수준이라 실제 부재가 합쳐지거나 누락돼 보일 수 있습니다.'
        else:
            hidden_detail_label = 'heuristic preview라 shape reading 중심입니다. exact member set과 topology는 아직 확정되지 않았습니다.'

        if density_tier == 'sparse':
            recommended_visibility_mode = 'trace'
            visibility_recommendation = 'sparse case라 `trace`가 가장 읽기 쉽습니다. endpoint와 label을 최대로 보여줍니다.'
        elif density_tier == 'light':
            recommended_visibility_mode = 'clarify'
            visibility_recommendation = 'light density case라 `clarify`로 edge를 두껍게 하면 읽기 쉽습니다.'
        else:
            recommended_visibility_mode = 'auto'
            visibility_recommendation = '현재 density면 `auto`로도 충분하고, 필요하면 `focus`로 label만 더 올리면 됩니다.'

        exactness_signal_source_label = str(
            summary.get('preview_exactness_signal_source', '')
            or summary.get('preview_source_table', '')
            or summary.get('geometry_preview_source_table', '')
            or summary.get('topology_grounding_label', '')
            or summary.get('source_table', '')
            or 'n/a'
        )

        return {
            'preview_fidelity_tier_label': fidelity_tier,
            'preview_fidelity_label': fidelity_label,
            'preview_fidelity_note_label': fidelity_note,
            'preview_exactness_label': preview_exactness_label or topology_readiness_label or 'n/a',
            'preview_exactness_signal_source_label': exactness_signal_source_label,
            'preview_density_tier_label': density_tier,
            'preview_density_label': density_label,
            'preview_visibility_label': visibility_label,
            'preview_visibility_note_label': visibility_note,
            'preview_hidden_detail_label': hidden_detail_label,
            'preview_recommended_visibility_mode_label': recommended_visibility_mode,
            'preview_visibility_recommendation_label': visibility_recommendation,
        }

