    member_types = _unique_sorted_tokens([str(key).strip() for key in member_type_counts.keys() if str(key or '').strip()])

    family_row_map: dict[str, dict[str, Any]] = {}
    for row in portfolio_registry_rows:
        if not isinstance(row, dict):
            continue
        family_id = str(row.get('family_id', '') or '').strip()
        if not family_id:
            continue
        record = _empty_native_authoring_family_record(family_id)
        family_row_map[family_id] = _merge_native_authoring_family_record(record, row)

    for row in portfolio_ops_rows:
        if not isinstance(row, dict):
            continue
        family_id = str(row.get('family_id', '') or row.get('authoring_family_id', '') or '').strip()
        if not family_id:
            continue
        record = family_row_map.get(family_id, _empty_native_authoring_family_record(family_id))
        record = _merge_native_authoring_family_record(record, row)
        draft_label = str(row.get('draft_label', '') or '').strip()
        if draft_label and draft_label not in record.get('draft_labels', []):
            record.setdefault('draft_labels', []).append(draft_label)
        project_id = str(row.get('project_id', '') or '').strip()
        if project_id and project_id not in record.get('project_ids', []):
            record.setdefault('project_ids', []).append(project_id)
