                f"runtime_authoring={'PASS' if bool(native_authoring_evidence.get('runtime_authoring_ready')) else 'CHECK'} | "
                f"cells={int(native_authoring_evidence.get('mesh_cell_count', 0) or 0)} | "
                f"load_cases={int(native_authoring_evidence.get('load_case_count', 0) or 0)} | "
                f"loadcomb_lines={int(native_authoring_evidence.get('loadcomb_line_count', 0) or 0)} | "
                f"families_ready={int(native_authoring_evidence.get('ready_family_count', 0) or 0)}/"
