    rows: list[dict[str, Any]] = []
    for priority, spec in enumerate(candidate_specs, start=1):
        candidate_id = str(spec.get('id', '') or '')
        source_row = mega_candidates.get(candidate_id) or diversification_candidates.get(candidate_id) or {}
