def _outrigger_case_switch_markup(case_catalog: list[dict[str, Any]], current_entry_id: str) -> str:
    relevant = [
        row
        for row in case_catalog
        if 'OPSTOOL 606m Outrigger' in str(row.get('title', '') or '')
    ]
    if not relevant or not any(str(row.get('entry_id', '') or '') == current_entry_id for row in relevant):
        return ''

    title_pattern = re.compile(r'^OPSTOOL 606m Outrigger(?: (\d+))? (Baseline|AI Compare|After Only)$')
    grouped: dict[str, dict[str, Any]] = {}
    for row in relevant:
        title = str(row.get('title', '') or '')
        match = title_pattern.match(title)
        if not match:
            continue
        case_suffix = match.group(1) or ''
        case_key = case_suffix or 'representative'
        mode_key = {
            'Baseline': 'baseline',
            'AI Compare': 'compare',
            'After Only': 'after_only',
        }.get(str(match.group(2) or ''), 'baseline')
        bucket = grouped.setdefault(
            case_key,
            {
                'label': case_suffix or '대표',
                'sort_key': -1 if not case_suffix else int(case_suffix),
                'links': {},
            },
        )
        bucket['links'][mode_key] = row

    if not grouped:
        return ''

    cards: list[str] = []
    link_specs = [('baseline', 'baseline'), ('compare', 'ai compare'), ('after_only', 'after only')]
    for case_row in sorted(grouped.values(), key=lambda row: int(row.get('sort_key', 0))):
        links = []
        for mode_key, label in link_specs:
            target = case_row['links'].get(mode_key)
            if not isinstance(target, dict):
                links.append(f"<span class='outrigger-switch-link is-disabled'>{label}</span>")
                continue
            is_current = str(target.get('entry_id', '') or '') == current_entry_id
            links.append(
                f"<a class='outrigger-switch-link{' is-current' if is_current else ''}' "
                f"href='{html.escape(str(target.get('href', '#') or '#'), quote=True)}'>{label}</a>"
            )
        cards.append(
            "<div class='outrigger-switch-card'>"
            f"<div class='outrigger-switch-case'>case {html.escape(str(case_row.get('label', '대표')), quote=True)}</div>"
            "<div class='outrigger-switch-links'>"
            + ''.join(links) +
            "</div></div>"
        )

    return (
        "<section class='section'>"
        "<div class='panel span-12'>"
        "<h2>606m Outrigger Case Switch</h2>"
        "<p class='lead'>같은 606m 아웃리거 family 안에서 baseline, AI compare, after-only optimized 3D를 바로 전환합니다.</p>"
        f"<div class='outrigger-switch-grid'>{''.join(cards)}</div>"
        "</div>"
        "</section>"
    )


def _midas_case_switch_markup(case_catalog: list[dict[str, Any]], current_entry_id: str) -> str:
    relevant = [
        row
        for row in case_catalog
        if str(row.get('entry_id', '') or '') in {
            'midas33_release_compare',
            'midas33_original_baseline',
            'midas33_optimized_roundtrip',
            'midas33_pr_recheck_baseline',
        }
    ]
    if not relevant or not any(str(row.get('entry_id', '') or '') == current_entry_id for row in relevant):
        return ''
    label_map = {
        'midas33_release_compare': 'release compare',
        'midas33_original_baseline': 'original baseline',
        'midas33_optimized_roundtrip': 'optimized roundtrip',
        'midas33_pr_recheck_baseline': 'pr recheck baseline',
    }
    by_id = {str(row.get('entry_id', '') or ''): row for row in relevant}
    links: list[str] = []
    for entry_id in label_map:
        target = by_id.get(entry_id)
        if not isinstance(target, dict):
            links.append(f"<span class='outrigger-switch-link is-disabled'>{label_map[entry_id]}</span>")
            continue
        is_current = entry_id == current_entry_id
        links.append(
            f"<a class='outrigger-switch-link{' is-current' if is_current else ''}' "
            f"href='{html.escape(str(target.get('href', '#') or '#'), quote=True)}'>{html.escape(label_map[entry_id], quote=True)}</a>"
        )
    return (
        "<section class='section'>"
        "<div class='panel span-12'>"
        "<h2>MIDAS 33 Case Switch</h2>"
        "<p class='lead'>같은 MIDAS 33 family 안에서 baseline, compare, optimized, recheck 케이스를 바로 바꿔 보며 3D와 evidence를 함께 읽습니다.</p>"
        "<div class='outrigger-switch-grid'>"
        "<div class='outrigger-switch-card'>"
        "<div class='outrigger-switch-case'>midas 33 family</div>"
        "<div class='outrigger-switch-links'>"
        + ''.join(links) +
        "</div></div></div></div></section>"
    )


def _catalog_support_script() -> str:
    return """
<script>
(() => {
  const select = document.getElementById('case-catalog-select');
  const search = document.getElementById('case-catalog-search');
  const filters = Array.from(document.querySelectorAll('[data-catalog-filter]'));
  const chips = Array.from(document.querySelectorAll('[data-case-catalog-jump][data-catalog-group]'));
  const options = select ? Array.from(select.querySelectorAll('option[data-catalog-group]')) : [];
  const summary = document.getElementById('catalog-filter-summary');

  const syncCatalogFilter = (group) => {
    const current = String(group || 'all');
    const keyword = String((search && search.value) || '').trim().toLowerCase();
    let visibleCount = 0;
    let readyCount = 0;
    let previewCount = 0;
    let crosscheckCount = 0;
    filters.forEach((button) => {
      button.classList.toggle('is-active', String(button.dataset.catalogFilter || 'all') === current);
    });
    chips.forEach((chip) => {
      const text = `${chip.textContent || ''} ${chip.getAttribute('href') || ''}`.toLowerCase();
      const previewState = String(chip.dataset.previewState || '');
      const previewBucket = String(chip.dataset.previewBucket || '');
      const caseFamily = String(chip.dataset.caseFamily || '');
      const visibility = String(chip.dataset.catalogVisibility || 'featured');
      const hasCrosscheck = String(chip.dataset.hasCrosscheck || '') === 'true';
      const isUpgradeCandidate = String(chip.dataset.upgradeCandidate || '') === 'true';
      const isCurrent = String(chip.dataset.isCurrent || '') === 'true';
      const matchedGroup =
        current === 'all' ||
        (current === 'featured' && visibility === 'featured') ||
        (current === 'secondary' && visibility === 'secondary') ||
        String(chip.dataset.catalogPrimary || '') === current ||
        (current === 'midas-33' && caseFamily === 'midas-33') ||
        (current === 'opensees' && caseFamily === 'opensees') ||
        (current === 'support-source' && caseFamily === 'support-source') ||
        (current === 'synthetic' && caseFamily === 'synthetic') ||
        (current === 'deep-artifacts' && visibility === 'deep-artifact') ||
        (current === 'verified-preview' && previewState === 'verified preview') ||
        (current === 'hint-preview' && previewBucket === 'hint-preview') ||
        (current === 'raw-preview' && previewBucket === 'raw-preview') ||
        (current === 'table-local-preview' && previewBucket === 'table-local-preview') ||
        (current === 'heuristic-preview' && previewBucket === 'heuristic-preview') ||
        (current === 'crosscheck' && hasCrosscheck) ||
        (current === 'no-preview' && previewState === 'no preview yet') ||
        (current === 'promote-next' && isUpgradeCandidate);
      const matchedSearch = !keyword || text.includes(keyword);
      const matched = (matchedGroup && matchedSearch) || isCurrent;
      chip.hidden = !matched;
      if (matched) {
        visibleCount += 1;
        if (String(chip.dataset.has3d || '') === 'true') readyCount += 1;
        if (previewState) previewCount += 1;
        if (hasCrosscheck) crosscheckCount += 1;
      }
    });
    options.forEach((option) => {
      const text = `${option.textContent || ''} ${option.value || ''}`.toLowerCase();
      const previewState = String(option.dataset.previewState || '');
      const previewBucket = String(option.dataset.previewBucket || '');
      const caseFamily = String(option.dataset.caseFamily || '');
      const visibility = String(option.dataset.catalogVisibility || 'featured');
      const hasCrosscheck = String(option.dataset.hasCrosscheck || '') === 'true';
      const isUpgradeCandidate = String(option.dataset.upgradeCandidate || '') === 'true';
      const isCurrent = String(option.dataset.isCurrent || '') === 'true';
      const matchedGroup =
        current === 'all' ||
        (current === 'featured' && visibility === 'featured') ||
        (current === 'secondary' && visibility === 'secondary') ||
        String(option.dataset.catalogPrimary || '') === current ||
        (current === 'midas-33' && caseFamily === 'midas-33') ||
        (current === 'opensees' && caseFamily === 'opensees') ||
        (current === 'support-source' && caseFamily === 'support-source') ||
        (current === 'synthetic' && caseFamily === 'synthetic') ||
        (current === 'deep-artifacts' && visibility === 'deep-artifact') ||
        (current === 'verified-preview' && previewState === 'verified preview') ||
        (current === 'hint-preview' && previewBucket === 'hint-preview') ||
        (current === 'raw-preview' && previewBucket === 'raw-preview') ||
        (current === 'table-local-preview' && previewBucket === 'table-local-preview') ||
        (current === 'heuristic-preview' && previewBucket === 'heuristic-preview') ||
        (current === 'crosscheck' && hasCrosscheck) ||
        (current === 'no-preview' && previewState === 'no preview yet') ||
        (current === 'promote-next' && isUpgradeCandidate);
      const matchedSearch = !keyword || text.includes(keyword);
      const matched = (matchedGroup && matchedSearch) || isCurrent;
      option.hidden = !matched;
    });
    if (summary) {
      const labelMap = {
        'featured': 'featured entries',
        'secondary': 'secondary entries',
        'all': 'all entries',
        '3d': '3d-ready cases',
        'midas-33': 'midas 33 cases',
        'opensees': 'opensees detailed cases',
        'support-source': 'support source 3d cases',
        'synthetic': 'synthetic 3d cases',
        'ai-data': 'ai data entries',
        'registered': 'registered catalog entries',
        'deep-artifacts': 'deep artifacts',
        'verified-preview': 'verified preview entries',
        'hint-preview': 'hint preview entries',
        'raw-preview': 'raw preview entries',
        'table-local-preview': 'table-local preview entries',
        'heuristic-preview': 'other heuristic preview entries',
        'crosscheck': 'cross-check available entries',
        'no-preview': 'no preview entries',
        'promote-next': 'upgrade candidates',
      };
      summary.textContent = `showing ${visibleCount} entries | 3d_ready=${readyCount} | preview=${previewCount} | crosscheck=${crosscheckCount} | filter=${labelMap[current] || current}${keyword ? ` | search=${keyword}` : ''}`;
    }
    if (select) {
      const selectedOption = select.options[select.selectedIndex];
      if (selectedOption && selectedOption.hidden) {
        const fallback = options.find((option) => !option.hidden);
        if (fallback) select.value = fallback.value;
      }
    }
  };

  if (select) {
    select.addEventListener('change', (event) => {
      const href = String(event.target.value || '');
      if (href) window.location.href = href;
    });
  }
  filters.forEach((button) => {
    button.addEventListener('click', () => syncCatalogFilter(String(button.dataset.catalogFilter || 'all')));
  });
  if (search) {
    search.addEventListener('input', () => {
      const active = filters.find((button) => button.classList.contains('is-active'));
      syncCatalogFilter(String((active && active.dataset.catalogFilter) || 'all'));
    });
  }
  syncCatalogFilter('featured');
})();
</script>
"""


