    def _uint_probe_value_rows(prefix: str, probe: dict[str, Any]) -> str:
        if not probe:
            return ''
        rows = [
            (f'{prefix} records_scanned', str(int(probe.get('records_scanned', 0) or 0))),
            (f'{prefix} active small uint records', str(int(probe.get('active_small_uint_record_count', 0) or 0))),
            (f'{prefix} layout state', str(probe.get('layout_state_label', 'n/a') or 'n/a')),
            (f'{prefix} dominant record ratio', str(round(_safe_float(probe.get('dominant_record_ratio', 0.0)), 3))),
            (f'{prefix} dominant record count', str(int(probe.get('dominant_record_count', 0) or 0))),
            (f'{prefix} small uint slot counts', ', '.join(str(int(item)) for item in (probe.get('small_uint_slot_counts') or [])) or 'n/a'),
            (f'{prefix} nonzero slot counts', ', '.join(str(int(item)) for item in (probe.get('nonzero_slot_counts') or [])) or 'n/a'),
            (f'{prefix} likely identifier slots', _format_int_list_label(probe.get('likely_identifier_slots'))),
            (f'{prefix} likely counter slots', _format_int_list_label(probe.get('likely_counter_slots'))),
            (f'{prefix} likely packed pairs', _format_slot_pair_list_label(probe.get('likely_packed_identifier_pairs'))),
            (f'{prefix} slot pattern probe', _format_slot_pattern_probe_label(probe)),
            (f'{prefix} adjacent pair probe', _format_adjacent_pair_probe_label(probe)),
            (f'{prefix} dominant record hex', str(probe.get('dominant_record_hex', 'n/a') or 'n/a')),
            (
                f'{prefix} sample small uint records',
                ' | '.join(
                    ', '.join(str(int(value)) for value in row)
                    for row in (probe.get('sample_small_uint_records') or [])[:3]
                    if isinstance(row, list)
                ) or 'n/a',
            ),
        ]
        return ''.join(
            "<div class='meta-row'>"
            f"<div class='meta-key'>{html.escape(label, quote=True)}</div>"
            f"<div class='meta-value'>{html.escape(value, quote=True)}</div>"
            "</div>"
            for label, value in rows
        )

