def _metric_rows(cards: list[dict[str, str]], *, shell_class: str = "card") -> str:
    return ''.join(
        render_card_title_block(
            kicker=html.escape(str(card.get('label', '') or ''), quote=True),
            title=html.escape(str(card.get('value', '') or ''), quote=True),
            copy=html.escape(str(card.get('note', '') or ''), quote=True),
            shell_tag="article",
            shell_class=shell_class,
            kicker_tag="div",
            kicker_class="eyebrow",
            title_tag="div",
            title_class="value",
            copy_tag="div",
            copy_class="note",
            quote="'",
        )
        for card in cards
    )


def _bars(rows: list[dict[str, Any]], label_key: str = 'label', value_key: str = 'changed_group_count') -> str:
    max_value = max([float(row.get(value_key, 0) or 0) for row in rows] + [1.0])
    parts = []
    for row in rows:
        value = float(row.get(value_key, 0) or 0)
        width = 12 if max_value <= 0 else max(12, int((value / max_value) * 100))
        parts.append(
            f"<div class='bar-row'><div class='bar-label'>{row.get(label_key,'')}</div><div class='bar-track'><div class='bar-fill' style='width:{width}%'></div></div><div class='bar-value'>{value:g}</div></div>"
        )
    return ''.join(parts)


def _story_table(rows: list[dict[str, Any]]) -> str:
    parts=[]
    for row in rows:
        parts.append(
            f"<tr class='story-change-row' data-story-band='{int(row.get('story_band', 0) or 0)}' data-zone-label='{str(row.get('zone_label', '') or 'unknown')}' data-member-type='{str(row.get('member_type', '') or 'unknown')}'>"
            f"<td>{row.get('story_band','')}</td>"
            f"<td>{row.get('zone_label','')}</td>"
            f"<td>{row.get('member_type','')}</td>"
            f"<td>{int(row.get('changed_group_count',0) or 0)}</td>"
            f"<td>{float(row.get('cost_proxy_delta_sum',0.0) or 0.0):.2f}</td>"
            f"<td>{float(row.get('constructability_delta_sum',0.0) or 0.0):.3f}</td>"
            f"<td>{float(row.get('max_dcr_after_max',0.0) or 0.0):.3f}</td>"
            '</tr>'
        )
    return ''.join(parts)


def _story_zone_matrix(story_zone_map: dict[str, Any]) -> str:
    zones = [str(zone) for zone in (story_zone_map.get('zones') or [])]
    rows = [row for row in (story_zone_map.get('rows') or []) if isinstance(row, dict)]
    max_abs_cost = _safe_float(story_zone_map.get('max_abs_cost_proxy_delta', 0.0), 0.0)
    head = ''.join(f"<th>{zone}</th>" for zone in zones)
    body_parts = []
    for row in rows:
        cells_html = []
        for cell in row.get('zones', []):
            groups = int(cell.get('changed_group_count', 0) or 0)
            cost_delta = _safe_float(cell.get('cost_proxy_delta_sum', 0.0))
            ratio = 0.0 if max_abs_cost <= 0 else min(1.0, abs(cost_delta) / max_abs_cost)
            if groups <= 0:
                tone = "rgba(217, 216, 211, 0.35)"
                border = "rgba(176, 171, 161, 0.45)"
            elif cost_delta <= 0:
                tone = f"rgba(31, 122, 79, {0.18 + ratio * 0.42:.3f})"
                border = "rgba(31, 122, 79, 0.45)"
            else:
                tone = f"rgba(217, 111, 50, {0.18 + ratio * 0.42:.3f})"
                border = "rgba(185, 96, 43, 0.45)"
            cells_html.append(
                "<td>"
                f"<div class='zone-cell' data-story-band='{int(cell.get('story_band', 0) or 0)}' data-zone-label='{str(cell.get('zone_label', '') or 'unknown')}' "
                f"data-member-types='{','.join(str(item) for item in (cell.get('member_type_list') or []))}' "
                f"data-dominant-member-type='{str(cell.get('dominant_member_type', '') or 'n/a')}' style='background:{tone}; border-color:{border}'>"
                f"<div class='zone-groups'>groups={groups}</div>"
                f"<div class='zone-meta'>costΔ={cost_delta:.1f}</div>"
                f"<div class='zone-meta'>dcr={_safe_float(cell.get('max_dcr_after_max', 0.0)):.3f}</div>"
                f"<div class='zone-member'>{str(cell.get('member_mix_label', 'n/a') or 'n/a')}</div>"
                "</div>"
                "</td>"
            )
        body_parts.append(
            "<tr>"
            f"<th>S{int(row.get('story_band', 0)):02d}</th>"
            f"{''.join(cells_html)}"
            "</tr>"
        )
    return (
        "<table class='zone-matrix'>"
        "<thead><tr><th>Story</th>"
        f"{head}"
        "</tr></thead>"
        f"<tbody>{''.join(body_parts)}</tbody>"
        "</table>"
    )


def _blocked_cards(rows: list[dict[str, Any]]) -> str:
    parts=[]
    for row in rows:
        parts.append(
            "<div class='blocked-card'>"
            f"<div class='blocked-title'>{row.get('benchmark_family','review_boundary')}</div>"
            f"<div class='blocked-meta'>priority={row.get('priority','n/a')} | owner={row.get('owner','n/a')}</div>"
            f"<div class='blocked-meta'>assignee={row.get('assignee_name','unassigned') or 'unassigned'} | assignment={row.get('assignment_status','unknown') or 'unknown'}</div>"
            f"<div class='blocked-meta'>followup={row.get('followup_action','n/a')} | sla={row.get('sla_state','n/a')} | age={row.get('age_bucket','n/a')}</div>"
            f"<div class='blocked-meta'>approve_all={row.get('preview_if_all_closed_reason_code','n/a')} | reject_one={row.get('preview_if_rejected_reason_code','n/a')}</div>"
            '</div>'
        )
    return ''.join(parts)


def _overlay_filter_chips(rows: list[dict[str, Any]], *, group: str) -> str:
    parts = []
    for row in rows:
        label = str(row.get('label', '') or 'unknown')
        display_label = label.replace('_', ' ').strip() or 'unknown'
        count = int(row.get('count', 0) or 0)
        parts.append(
            f"<button type='button' class='filter-chip' data-filter-group='{group}' data-filter-value='{label}'>"
            f"{html.escape(display_label, quote=True)}<span>{count}</span></button>"
        )
    return ''.join(parts)


def _overlay_legend_chips(rows: list[dict[str, Any]]) -> str:
    parts = []
    for row in rows:
        label = str(row.get('label', '') or 'unknown')
        count = int(row.get('count', 0) or 0)
        color = str(row.get('color', '#5b6470') or '#5b6470')
        parts.append(
            "<div class='legend-chip'>"
            f"<span class='legend-swatch' style='background:{color}'></span>"
            f"<span>{label}</span>"
            f"<span class='legend-count'>{count}</span>"
            "</div>"
        )
    return ''.join(parts)


def _overlay_member_type_quick_notes(rows: list[dict[str, Any]]) -> str:
    descriptions = {
        'beam': 'beam은 보통 수평 골조입니다. 평면에서 길게 이어지는 선부터 보면 위치가 가장 빨리 읽힙니다.',
        'wall': 'wall은 코어·전단벽 계열입니다. 수직 영향과 횡력 저항 변화가 같이 걸릴 가능성이 큽니다.',
        'slab': 'slab은 바닥판입니다. 면으로 넓게 퍼진 부재라 다른 타입보다 수가 크게 보일 수 있습니다.',
        'column': 'column은 수직 지지 부재입니다. 층 간 하중 전달이나 외곽 frame 조정과 자주 같이 읽습니다.',
        'other': 'other는 기타 보조 부재입니다. 먼저 beam·wall·slab·column을 보고 남는 항목을 확인하면 덜 헷갈립니다.',
        'unknown': 'unknown은 아직 member type 해석이 명확하지 않은 항목입니다. family와 selected member 패널을 함께 보는 편이 안전합니다.',
    }
    parts = []
    for row in rows:
        label = str(row.get('label', '') or 'unknown')
        count = int(row.get('count', 0) or 0)
        color = str(row.get('color', '#5b6470') or '#5b6470')
        note = descriptions.get(label, descriptions['other'])
        parts.append(
            "<div class='overlay-type-note'>"
            f"<span class='legend-swatch' style='background:{color}'></span>"
            f"<strong>{label}</strong>"
            f"<span class='overlay-type-count'>{count}</span>"
            f"<span class='overlay-type-copy'>{note}</span>"
            "</div>"
        )
    return ''.join(parts)


def _overlay_change_locator_rows_markup(rows: list[dict[str, Any]]) -> str:
    parts = []
    for row in rows:
        member_id = html.escape(str(row.get('member_id', '') or 'n/a'), quote=True)
        group_id = html.escape(str(row.get('group_id', '') or 'n/a'), quote=True)
        family = html.escape(str(row.get('action_family', '') or 'unknown'), quote=True)
        member_type = html.escape(str(row.get('member_type', '') or 'unknown'), quote=True)
        story_zone = html.escape(str(row.get('story_zone_label', '') or 'unknown'), quote=True)
        action_label = html.escape(str(row.get('action_name_label', '') or 'n/a'), quote=True)
        change_semantics = html.escape(str(row.get('change_semantics_label', '') or '같은 자리 / 속성 조정'), quote=True)
        spatial = html.escape(str(row.get('spatial_read_label', '') or '같은 자리 속성 조정'), quote=True)
        optimization = html.escape(str(row.get('optimization_meaning_label', '') or '속성 최적화'), quote=True)
        cost_delta = html.escape(str(row.get('cost_delta_label', '') or '0.0'), quote=True)
        constructability = html.escape(str(row.get('constructability_delta_label', '') or '0.0'), quote=True)
        gate = html.escape(str(row.get('selection_gate_label', '') or 'n/a'), quote=True)
        reason = html.escape(str(row.get('reason_selected_label', '') or 'n/a'), quote=True)
        parts.append(
            "<button type='button' class='overlay-change-locator-row' "
            f"data-overlay-locator-member='{member_id}' "
            f"data-overlay-locator-group='{group_id}' "
            f"data-overlay-row-id='{html.escape(str(row.get('overlay_row_id', '') or ''), quote=True)}' "
            f"data-family='{family}' "
            f"data-member-type='{member_type}' "
            f"data-story-band='{html.escape(str(row.get('story_band', '') or ''), quote=True)}' "
            f"data-selected-event-index='{html.escape(str(row.get('selected_event_index', '') or ''), quote=True)}' "
            f"data-zone-label='{html.escape(str(row.get('zone_label', '') or 'unknown'), quote=True)}'>"
            "<div class='overlay-change-locator-head'>"
            f"<strong>{member_id}</strong>"
            f"<span>{story_zone}</span>"
            "</div>"
            f"<div class='overlay-change-locator-copy'>{change_semantics} | {optimization}</div>"
            f"<div class='overlay-change-locator-meta'><span>{action_label}</span><span>{spatial}</span><span>costΔ={cost_delta}</span><span>constructabilityΔ={constructability}</span><span>gate={gate}</span><span>{reason}</span></div>"
            "</button>"
        )
    return ''.join(parts)


def _overlay_change_locator_groups(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    groups: dict[tuple[int, str, str, str], dict[str, Any]] = {}
    for row in rows:
        story_band = int(row.get('story_band', 0) or 0)
        zone_label = str(row.get('zone_label', '') or 'unknown')
        action_family = str(row.get('action_family', '') or 'unknown')
        member_type = str(row.get('member_type', '') or 'unknown')
        key = (story_band, zone_label, action_family, member_type)
        bucket = groups.setdefault(
            key,
            {
                'story_band': story_band,
                'zone_label': zone_label,
                'story_zone_label': str(row.get('story_zone_label', '') or f'{_story_band_label(story_band)} / {zone_label}'),
                'action_family': action_family,
                'action_family_label': _humanize_overlay_label(action_family),
                'member_type': member_type,
                'member_type_label': _humanize_overlay_label(member_type),
                'change_semantics_label': str(row.get('change_semantics_label', '') or '같은 자리 / 속성 조정'),
                'optimization_meaning_label': str(row.get('optimization_meaning_label', '') or '속성 최적화'),
                'spatial_read_label': str(row.get('spatial_read_label', '') or '위치 이동보다 같은 자리 속성 조정'),
                'members': [],
                'member_count': 0,
                'cost_delta_total': 0.0,
                'constructability_delta_total': 0.0,
                'representative_modification_label': str(row.get('modification_snapshot_label', '') or '같은 자리 속성 조정'),
                'representative_impact_label': str(row.get('impact_snapshot_label', '') or 'cost / dcr 중심 영향 검토'),
                'representative_note': str(row.get('before_after_snapshot_note', '') or ''),
                'representative_members': [],
            },
        )
        bucket['members'].append(row)
        bucket['member_count'] = int(bucket.get('member_count', 0) or 0) + 1
        bucket['cost_delta_total'] = round(_safe_float(bucket.get('cost_delta_total', 0.0)) + _safe_float(row.get('cost_delta', 0.0)), 3)
        bucket['constructability_delta_total'] = round(_safe_float(bucket.get('constructability_delta_total', 0.0)) + _safe_float(row.get('constructability_delta', 0.0)), 3)
        if abs(_safe_float(row.get('cost_delta', 0.0))) > abs(_safe_float(bucket.get('cost_delta_total', 0.0))) / max(int(bucket['member_count']), 1):
            bucket['representative_modification_label'] = str(row.get('modification_snapshot_label', '') or bucket['representative_modification_label'])
            bucket['representative_impact_label'] = str(row.get('impact_snapshot_label', '') or bucket['representative_impact_label'])
            bucket['representative_note'] = str(row.get('before_after_snapshot_note', '') or bucket['representative_note'])

    ordered = sorted(
        groups.values(),
        key=lambda item: (
            -int(item.get('story_band', 0) or 0),
            str(item.get('zone_label', '') or ''),
            -abs(_safe_float(item.get('cost_delta_total', 0.0), 0.0)),
            str(item.get('action_family', '') or ''),
            str(item.get('member_type', '') or ''),
        ),
    )
    for item in ordered:
        item['members'] = sorted(
            list(item.get('members', [])),
            key=lambda row: (
                -abs(_safe_float(row.get('cost_delta', 0.0), 0.0)),
                str(row.get('member_id', '') or ''),
            ),
        )
        item['representative_members'] = [
            {
                'member_id': str(row.get('member_id', '') or 'n/a'),
                'story_band': int(row.get('story_band', 0) or 0),
                'zone_label': str(row.get('zone_label', '') or 'unknown'),
                'label': str(
                    row.get('modification_snapshot_label', '')
                    or row.get('impact_snapshot_label', '')
                    or row.get('before_after_snapshot_note', '')
                    or '같은 자리 속성 조정'
                ),
            }
            for row in item['members'][:3]
        ]
    return ordered


def _overlay_change_locator_groups_markup(groups: list[dict[str, Any]]) -> str:
    parts = []
    for group in groups:
        members = list(group.get('members', []))
        member_markup = _overlay_change_locator_rows_markup(members)
        cost_delta_total = _safe_float(group.get('cost_delta_total', 0.0))
        constructability_delta_total = _safe_float(group.get('constructability_delta_total', 0.0))
        cost_tone = 'is-good' if cost_delta_total < -1e-9 else 'is-warn' if cost_delta_total > 1e-9 else 'is-neutral'
        constructability_tone = 'is-good' if constructability_delta_total < -1e-9 else 'is-warn' if constructability_delta_total > 1e-9 else 'is-neutral'
        representative_members_markup = ''.join(
            (
                f"<button type='button' class='overlay-change-locator-representative' "
                f"data-overlay-representative-member='{html.escape(str(member.get('member_id', '') or ''), quote=True)}' "
                f"title='{html.escape(str(member.get('label', '') or ''), quote=True)}'>"
                f"<strong>{html.escape(str(member.get('member_id', '') or 'n/a'), quote=True)}</strong>"
                f"<span>{html.escape(str(member.get('label', '') or '같은 자리 속성 조정'), quote=True)}</span>"
                "</button>"
            )
            for member in list(group.get('representative_members', []))
        )
        parts.append(
            f"<details class='overlay-change-locator-group' data-family='{html.escape(str(group.get('action_family', '') or 'unknown'), quote=True)}' "
            f"data-member-type='{html.escape(str(group.get('member_type', '') or 'unknown'), quote=True)}' "
            f"data-story-band='{int(group.get('story_band', 0) or 0)}' "
            f"data-zone-label='{html.escape(str(group.get('zone_label', '') or 'unknown'), quote=True)}'>"
            "<summary class='overlay-change-locator-group-summary'>"
            "<div class='overlay-change-locator-group-head'>"
            f"<strong>{html.escape(str(group.get('story_zone_label', '') or 'unknown'), quote=True)}</strong>"
            f"<span>{html.escape(str(group.get('action_family_label', '') or 'unknown'), quote=True)} · {html.escape(str(group.get('member_type_label', '') or 'unknown'), quote=True)}</span>"
            "</div>"
            f"<div class='overlay-change-locator-group-copy'>{html.escape(str(group.get('change_semantics_label', '') or '같은 자리 / 속성 조정'), quote=True)} | {html.escape(str(group.get('optimization_meaning_label', '') or '속성 최적화'), quote=True)}</div>"
            f"<div class='overlay-change-locator-group-summary-line'>{html.escape(str(group.get('story_zone_label', '') or 'unknown'), quote=True)}에서 {html.escape(str(group.get('member_type_label', '') or 'member'), quote=True)} {int(group.get('member_count', 0) or 0)}개를 {html.escape(str(group.get('action_family_label', '') or 'unknown'), quote=True)} 기준으로 먼저 묶어 본 그룹입니다.</div>"
            f"<div class='overlay-change-locator-group-meta'><span>members={int(group.get('member_count', 0) or 0)}</span><span class='overlay-change-locator-group-impact-pill {cost_tone}'>costΔ sum={cost_delta_total:.3f}</span><span class='overlay-change-locator-group-impact-pill {constructability_tone}'>constructabilityΔ sum={constructability_delta_total:.3f}</span><span>{html.escape(str(group.get('spatial_read_label', '') or '같은 자리 속성 조정'), quote=True)}</span></div>"
            f"<div class='overlay-change-locator-group-note'>대표 수정: {html.escape(str(group.get('representative_modification_label', '') or '같은 자리 속성 조정'), quote=True)} | 영향: {html.escape(str(group.get('representative_impact_label', '') or 'cost / dcr 중심 영향 검토'), quote=True)}</div>"
            "<div class='overlay-change-locator-group-tools'>"
            "<div class='overlay-change-locator-group-tools-copy'>대표 member를 바로 눌러 상세로 이동하거나, 아래 버튼으로 이 그룹만 좁혀 볼 수 있습니다.</div>"
            f"<button type='button' class='overlay-change-locator-group-focus' data-overlay-group-focus='true' data-family='{html.escape(str(group.get('action_family', '') or 'unknown'), quote=True)}' data-member-type='{html.escape(str(group.get('member_type', '') or 'unknown'), quote=True)}' data-story-band='{int(group.get('story_band', 0) or 0)}' data-zone-label='{html.escape(str(group.get('zone_label', '') or 'unknown'), quote=True)}' data-member-count='{int(group.get('member_count', 0) or 0)}' data-cost-delta-total='{cost_delta_total:.6f}' data-constructability-delta-total='{constructability_delta_total:.6f}'>이 그룹만 보기</button>"
            "</div>"
            f"<div class='overlay-change-locator-group-representatives'>{representative_members_markup}</div>"
            "</summary>"
            f"<div class='overlay-change-locator-group-body'><div class='overlay-change-locator'>{member_markup}</div></div>"
            "</details>"
        )
    return ''.join(parts)


def _gallery(tiles: list[dict[str, str]]) -> str:
    return ''.join(
        "<a class='gallery-tile' href='{href}'>"
        "<div class='gallery-preview-shell'><img class='gallery-preview' src='{href}' alt='{title}' loading='lazy'></div>"
        "<div class='gallery-head'>"
        "<div class='gallery-title'>{title}</div>"
        "{badge_html}"
        "</div>"
        "<div class='gallery-desc'>{description}</div>"
        "<div class='gallery-path'>{path}</div>"
        "</a>".format(
            href=tile['href'],
            title=tile['title'],
            path=tile['path'],
            description=tile.get('description', ''),
            badge_html=(
                f"<div class='gallery-badge is-{tile.get('badge_tone', 'plain')}'>{tile.get('badge', '')}</div>"
                if str(tile.get('badge', '')).strip()
                else ""
            ),
        )
        for tile in tiles
    )


def _results_metric_grid(rows: list[dict[str, str]]) -> str:
    return ''.join(
        "<div class='results-metric-card' data-deep-link-selection-key='results-companion:metrics' data-deep-link-focus-key='{focus_key}'>"
        "<div class='results-metric-label'>{label}</div>"
        "<div class='results-metric-value'>{value}</div>"
        "</div>".format(
            focus_key=html.escape(f"metric:{_safe_slug(str(row.get('label', 'metric') or 'metric'))}", quote=True),
            label=html.escape(str(row.get('label', 'metric') or 'metric'), quote=True),
            value=html.escape(str(row.get('value', 'n/a') or 'n/a'), quote=True),
        )
        for row in rows
    )


def _results_check_row(rows: list[str]) -> str:
    if not rows:
        return "<span class='results-check-pill' data-deep-link-selection-key='results-companion:checks' data-deep-link-focus-key='check:no-linked-checks'>no linked checks</span>"
    return ''.join(
        f"<span class='results-check-pill' data-deep-link-selection-key='results-companion:checks' data-deep-link-focus-key='check:{html.escape(_safe_slug(str(row or 'check')), quote=True)}'>{html.escape(str(row or 'check'), quote=True)}</span>"
        for row in rows
    )


def _results_sparkline_svg(
    points: list[tuple[float, float]],
    *,
    color: str,
    label: str,
    value_label: str = '',
    width: int = 360,
    height: int = 112,
) -> str:
    if not points:
        return "<div class='note'>trace unavailable</div>"
    min_x, max_x, min_y, max_y = _point_bounds(points)
    if abs(max_y - min_y) < 1e-9:
        center = (min_y + max_y) * 0.5
        min_y = center - 1.0
        max_y = center + 1.0
    polyline = _polyline_path(points, width=width, height=height, padding=18.0, bounds=(min_x, max_x, min_y, max_y))
    min_label = _format_result_metric(min_y, decimals=3)
    max_label = _format_result_metric(max_y, decimals=3)
    end_value = _format_result_metric(points[-1][1], decimals=3)
    return (
        "<div class='results-mini-chart'>"
        "<div class='results-mini-chart-head'>"
        f"<strong>{html.escape(label, quote=True)}</strong>"
        f"<span>{html.escape(value_label or f'end={end_value}', quote=True)}</span>"
        "</div>"
        f"<svg viewBox='0 0 {width} {height}' class='results-mini-chart-svg' role='img' aria-label='{html.escape(label, quote=True)}'>"
        f"<rect x='0.5' y='0.5' width='{width - 1}' height='{height - 1}' rx='16' fill='#fffdfa' stroke='rgba(161,145,120,0.24)'/>"
        f"<polyline points='{polyline}' fill='none' stroke='{html.escape(color, quote=True)}' stroke-width='3.2' stroke-linecap='round' stroke-linejoin='round'/>"
        f"<text x='16' y='20' fill='#6e7a87' font-size='11'>max {html.escape(max_label, quote=True)}</text>"
        f"<text x='16' y='{height - 12}' fill='#6e7a87' font-size='11'>min {html.escape(min_label, quote=True)}</text>"
        "</svg>"
        "</div>"
    )


def _results_comparison_rows(
    rows: list[dict[str, Any]],
    *,
    higher_is_better: bool,
    mode: str = 'relative',
) -> str:
    if not rows:
        return "<div class='note'>comparison unavailable</div>"
    numeric_values = [_safe_float(row.get('value', 0.0), 0.0) for row in rows]
    max_value = max(numeric_values + [1e-9])
    parts = []
    for row in rows:
        value = _safe_float(row.get('value', 0.0), 0.0)
        if mode == 'percent':
            width = max(6, min(100, int(round(value * 100.0))))
        else:
            width = max(6, int(round((value / max_value) * 100.0))) if max_value > 0 else 6
        tone = 'is-good' if higher_is_better == (value >= max_value - 1e-12) else 'is-muted'
        parts.append(
            f"<div class='results-compare-row' data-deep-link-selection-key='results-detail:compare' data-deep-link-focus-key='compare:{html.escape(_safe_slug(str(row.get('label', 'comparison') or 'comparison')), quote=True)}'>"
            f"<div class='results-compare-label'>{html.escape(str(row.get('label', 'comparison') or 'comparison'), quote=True)}</div>"
            "<div class='results-compare-track'>"
            f"<div class='results-compare-fill {tone}' style='width:{width}%'></div>"
            "</div>"
            f"<div class='results-compare-value'>{html.escape(str(row.get('display', 'n/a') or 'n/a'), quote=True)}</div>"
            "</div>"
        )
    return ''.join(parts)


