        kind, tone, _ = _case_evidence_type_info(row)
        if kind == 'FIGURE':
            label = 'figure preview'
            return (
                "<div class='case-evidence-preview case-evidence-preview-image'>"
                f"<div class='case-evidence-preview-label'>{html.escape(label, quote=True)}</div>"
                f"<div class='gallery-preview-shell'><img class='gallery-preview' src='{html.escape(href, quote=True)}' alt='{html.escape(str(row.get('label', 'figure') or 'figure'), quote=True)}' loading='lazy'></div>"
                "</div>"
            )
        return (
            "<div class='case-evidence-preview case-evidence-preview-card'>"
            f"<div class='case-evidence-preview-badge'>{html.escape(kind, quote=True)}</div>"
            f"<div class='case-evidence-preview-meta'>{html.escape(tone, quote=True)}</div>"
            "</div>"
        )
